def es_primo(n: int) -> bool:
    """Devuelve True si n es un número primo, False en caso contrario."""
    if n < 2:
        return False
    if n in (2, 3):
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False

    i = 5
    # Verifica divisores de la forma 6k ± 1 hasta sqrt(n)
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True


if __name__ == "__main__":
    # Ejemplos de uso
    pruebas = [1, 2, 3, 4, 5, 16, 17, 19, 20, 23, 24, 29, 97, 100]
    for num in pruebas:
        print(f"{num}: {'primo' if es_primo(num) else 'no primo'}")
